/* LoginMapper.insertLoginHis */
INSERT INTO TB_LOGIN_HIS(
    MEMBER_ID,
    LOGIN_IP,
    LOGIN_DT
)VALUES(
    #{memberId},
    #{loginIp},
    NOW()
)

mapper.update:
/* LoginMapper.updateUserFailCnt */
UPDATE
	TB_USER_INFO
SET
	FAIL_CNT = #{failCnt}
WHERE
	MEMBER_ID = #{memberId}

mapper.insert:
/* LoginMapper.insertSignUp */
INSERT INTO TB_USER_INFO (
	 MEMBER_ID
	,AUTH_GRP_CD
	,MEMBER_NM
	,MEMBER_PW
	,MASTER_CODE
	,MEMBER_EMAIL
	,MEMBER_BRTHDY
	,MEMBER_PHONE
	,MEMBER_POST
	,MEMBER_ADDR
	,MEMBER_ADDR_DETL
	,AGREE_YN
	,CONFM_YN
	,JOIN_DE
	,CONFM_ID
	,CONFM_DT
	,USE_YN
) VALUES (
	 #{memberId}
	,'1'
	,#{memberNm}
	,#{memberPw}
	,'1'
	,#{memberEmail}
	,#{memberBrthdy}
	,#{memberPhone}
	,#{memberPost}
	,#{memberAddr}
	,#{memberAddrDetl}
	,#{agreeYn}
	,'Y'
	,now()
	,'admin'
	,now()
	,'Y'
)

mapper.select:
/* LoginMapper.selectId */
SELECT
	MEMBER_ID	AS memberId
FROM
	TB_USER_INFO
WHERE
	MEMBER_NM = #{memberNm}
AND
	MEMBER_EMAIL = #{memberEmail}
AND
	MEMBER_BRTHDY = #{memberBrthdy}
AND
	MEMBER_PHONE = #{memberPhone}

